local function randomLimit(item)
    return HostApi.random("GoodsLimit", item.MinNum, item.MaxNum)
end

GoodsRandomPool = class()

function GoodsRandomPool:ctor(PoolId)
    self.PoolId = PoolId
    self.PoolTabs = {}
end

function GoodsRandomPool:addItemToPool(item)
    local tab = self.PoolTabs[item.Goods.TabId]
    if not tab then
        tab = {
            WeightSum = 0,
            Items = {}
        }
        self.PoolTabs[item.Goods.TabId] = tab
    end
    tab.WeightSum = tab.WeightSum + item.Weight
    table.insert(tab.Items, item)
end

function GoodsRandomPool:randomGoods(params)
    local goodsList = {}
    local paramArray = StringUtil.split(params, "#")
    local randomParams = {}
    for _, tab in pairs(paramArray) do
        local param = StringUtil.split(tab, "=")
        table.insert(randomParams, {
            TabId = tonumber(param[1]),
            Count = tonumber(param[2])
        })
    end
    for _, param in pairs(randomParams) do
        local old = self.PoolTabs[param.TabId]
        if old ~= nil then
            local tab = TableUtil.copyTable(self.PoolTabs[param.TabId])
            local count = math.min(param.Count, #tab.Items)
            while count > 0 do
                local random = HostApi.random("GoodsPool", 1, tab.WeightSum)
                local weight = 0
                for pos, item in pairs(tab.Items) do
                    weight = weight + item.Weight
                    if weight >= random then
                        table.insert(goodsList, {
                            goodsId = item.Goods.GoodsId,
                            limit = randomLimit(item)
                        })
                        tab.WeightSum = tab.WeightSum - item.Weight
                        table.remove(tab.Items, pos)
                        break
                    end
                end
                count = count - 1
            end
        end
    end
    return goodsList
end

return GoodsRandomPool